// Build the Slack message from the chatbot payload.
const p = $json.body || $json;
const intent = (p.intent || 'review').toUpperCase();
const emoji = intent === 'CV' ? ':briefcase:' : ':grey_question:';
const lines = [
  `${emoji} *Nuevo mensaje del chatbot* — intent: *${intent}*`,
  p.user_name ? `*Nombre:* ${p.user_name}` : null,
  p.user_email ? `*Email:* ${p.user_email}` : null,
  `*Mensaje:* ${p.message}`,
  p.page_url ? `*Página:* ${p.page_url}` : null,
  `\n_Responde en un *hilo* a este mensaje para contestarle al visitante._`,
  `\`conversation_id: ${p.conversation_id || 'n/a'}\``
].filter(Boolean);
return [{ json: { text: lines.join('\n'), conversation_id: p.conversation_id } }];
